'use client'

'use client'

import { move } from '@dnd-kit/helpers'
// Stalk UI component - requires PandaCSS setup and @stalk-ui/preset.
import { DragDropProvider } from '@dnd-kit/react'
import { useSortable } from '@dnd-kit/react/sortable'
import { createStyleContext } from '../../lib/stalk-ui/create-style-context'
import { GripVertical } from 'lucide-react'
import { createContext, forwardRef, useContext, useMemo } from 'react'
import { cx } from 'styled-system/css'
import { sortable as sortableRecipe } from 'styled-system/recipes'

import type { ButtonHTMLAttributes, HTMLAttributes, ReactNode } from 'react'

/** Matches dnd-kit's `UniqueIdentifier`. */
export type SortableId = number | string

const { StyleProvider, useSlotStyles } = /* @__PURE__ */ createStyleContext(sortableRecipe, {
  name: 'Sortable',
})

// The item shares its drag-handle ref down to `Sortable.Handle`. `null` means
// "no handle context" — Handle rendered outside an Item.
type HandleRef = (element: Element | null) => void
const SortableHandleContext = /* @__PURE__ */ createContext<HandleRef | null>(null)

export interface SortableProps<T extends { id: SortableId }> extends Omit<
  HTMLAttributes<HTMLDivElement>,
  'onDragEnd'
> {
  /** The ordered items. Each needs a stable `id`; this is the source of truth. */
  items: T[]
  /** Called with the reordered array when a drag settles into a new position. */
  onReorder: (items: T[]) => void
  /** The `Sortable.Item`s, one per entry in `items`. */
  children: ReactNode
}

/**
 * Headless drag-to-reorder list built on @dnd-kit. Controlled: you own `items`
 * and apply the `onReorder` result to your state. Keyboard and pointer dragging
 * (space to lift, arrows to move, space to drop) come from dnd-kit's default
 * sensors, so it is accessible out of the box. Compose it into reorderable lists,
 * sortable rows, or multi-column boards.
 */
export function SortableRoot<T extends { id: SortableId }>({
  items,
  onReorder,
  className,
  children,
  ...props
}: SortableProps<T>) {
  const styles = useMemo(() => sortableRecipe(), [])

  return (
    <DragDropProvider
      onDragEnd={(event) => {
        // `move` returns the same reference on a canceled/no-op drag.
        const next = move(items, event)
        if (next !== items) onReorder(next)
      }}
    >
      <StyleProvider value={styles}>
        <div className={cx(styles.root, className)} {...props}>
          {children}
        </div>
      </StyleProvider>
    </DragDropProvider>
  )
}

export interface SortableItemProps extends Omit<HTMLAttributes<HTMLDivElement>, 'id'> {
  /** Stable identifier matching the corresponding entry in `items` (dnd-kit id). */
  id: SortableId
  /** The item's current position in `items`. */
  index: number
}

export const SortableItem = /* @__PURE__ */ forwardRef<HTMLDivElement, SortableItemProps>(
  function SortableItem({ id, index, className, children, ...props }, forwardedRef) {
    const styles = useSlotStyles()
    const { ref, handleRef, isDragging } = useSortable({ id, index })

    const setRefs = (node: HTMLDivElement | null) => {
      ref(node)
      if (typeof forwardedRef === 'function') forwardedRef(node)
      else if (forwardedRef) forwardedRef.current = node
    }

    return (
      <SortableHandleContext.Provider value={handleRef}>
        <div
          ref={setRefs}
          className={cx(styles.item, className)}
          data-dragging={isDragging ? '' : undefined}
          {...props}
        >
          {children}
        </div>
      </SortableHandleContext.Provider>
    )
  },
)

export interface SortableHandleProps extends ButtonHTMLAttributes<HTMLButtonElement> {
  /** Accessible label for the drag handle (i18n). Default `'Drag to reorder'`. */
  label?: string
}

/**
 * Drag handle for a `Sortable.Item`. When present, only the handle initiates a
 * drag (the rest of the item stays interactive). Omit it to make the whole item
 * draggable. Renders a grip icon by default; pass children to override.
 */
export const SortableHandle = /* @__PURE__ */ forwardRef<HTMLButtonElement, SortableHandleProps>(
  function SortableHandle(
    { label = 'Drag to reorder', className, children, ...props },
    forwardedRef,
  ) {
    const styles = useSlotStyles()
    const handleRef = useContext(SortableHandleContext)
    if (handleRef === null) {
      throw new Error('Sortable.Handle must be rendered inside <Sortable.Item>.')
    }

    const setRefs = (node: HTMLButtonElement | null) => {
      handleRef(node)
      if (typeof forwardedRef === 'function') forwardedRef(node)
      else if (forwardedRef) forwardedRef.current = node
    }

    return (
      <button
        ref={setRefs}
        aria-label={label}
        className={cx(styles.handle, className)}
        type="button"
        {...props}
      >
        {children ?? <GripVertical aria-hidden="true" height={16} width={16} />}
      </button>
    )
  },
)

export const Sortable = /* @__PURE__ */ Object.assign(SortableRoot, {
  Handle: SortableHandle,
  Item: SortableItem,
  Root: SortableRoot,
})

'use client'

import {
  createContext,
  forwardRef,
  useContext,
  type ComponentPropsWithoutRef,
  type ComponentRef,
  type ElementType,
} from 'react'
// Stalk UI component - requires PandaCSS setup and @stalk-ui/preset.

type Slots = Record<string, string>

// Structural shape of a Panda slot recipe, kept deliberately minimal: we only
// rely on the callable (variants -> slot classes) and `splitVariantProps`. The
// variant (`V`) and slot (`S`) types are inferred from the call signature at the
// use site, so they stay precise without restating Panda's generated shape.
//
// `splitVariantProps` is typed loosely on purpose. Its `never` parameter is the
// trick that avoids `any`: because parameters are contravariant, a `never` param
// accepts any recipe's concrete signature — including Panda's generic,
// `DistributiveOmit`-returning one — without the variance clash an exact match
// produces. We never consume its return type (only its first element, re-narrowed
// below), so `unknown` tuple slots are enough.
interface Recipe<V, S extends Slots> {
  (props?: V): S
  splitVariantProps: (props: never) => [unknown, unknown]
}

interface CreateStyleContextOptions {
  name: string
}

const cx = (...classes: (string | false | null | undefined)[]): string => {
  let result = ''
  for (const value of classes) {
    if (typeof value === 'string' && value !== '') {
      if (result !== '') result += ' '
      result += value
    }
  }
  return result
}

const capitalize = (value: string): string =>
  value.length === 0 ? value : value.charAt(0).toUpperCase() + value.slice(1)

export function createStyleContext<V, S extends Slots>(
  recipe: Recipe<V, S>,
  { name }: CreateStyleContextOptions,
) {
  type TSlots = S
  type TVariants = NonNullable<V>

  // `recipe`'s real call/split signatures are erased to `Recipe<V, S>` here; recover
  // the two we actually invoke through contained assertions. This is where the
  // structural looseness above is paid back as precise local types — no `any`.
  const applyRecipe = recipe as unknown as (variantProps: Partial<TVariants>) => TSlots
  const splitVariantProps = recipe.splitVariantProps as (
    props: object,
  ) => [Partial<TVariants>, { className?: string } & Record<string, unknown>]

  const StyleContext = /* @__PURE__ */ createContext<TSlots | null>(null)

  const useSlotStyles = (): TSlots => {
    const styles = useContext(StyleContext)
    if (styles === null) {
      throw new Error(`${name} subcomponents must be rendered inside <${name}Root>.`)
    }
    return styles
  }

  // Escape hatch for roots that need custom rendering (e.g. applying a
  // `colorPalette` from a `tone` prop) while still feeding `withContext` slots.
  // Compute `recipe(variants)` in the root and wrap children in this provider.
  const StyleProvider = StyleContext.Provider

  // Per-part `displayName` so React DevTools shows `AccordionItem` rather than a
  // generic factory name. A factory can't use static function names, so this
  // assignment is the only option — and unlike the top-level mutations the repo
  // rules forbid, it runs inside the `/* @__PURE__ */`-annotated factory call on
  // a freshly created component, so unused parts still tree-shake (verified by
  // scripts/verify-tree-shaking.ts).
  function withRootProvider<TElement extends ElementType>(Component: TElement) {
    type Props = ComponentPropsWithoutRef<TElement> & Partial<TVariants>
    const Styled = /* @__PURE__ */ forwardRef<ComponentRef<TElement>, Props>(
      function StyledRoot(props, ref) {
        const [variantProps, rest] = splitVariantProps(props)
        const styles = applyRecipe(variantProps)
        const { className, ...passthrough } = rest
        const Element: ElementType = Component
        return (
          <StyleContext.Provider value={styles}>
            <Element ref={ref} className={cx(styles.root, className)} {...passthrough} />
          </StyleContext.Provider>
        )
      },
    )
    Styled.displayName = `${name}Root`
    return Styled
  }

  function withContext<TElement extends ElementType>(Component: TElement, slot: keyof TSlots) {
    type Props = ComponentPropsWithoutRef<TElement>
    const slotKey = String(slot)
    const Styled = /* @__PURE__ */ forwardRef<ComponentRef<TElement>, Props>(
      function StyledSlot(props, ref) {
        const styles = useSlotStyles()
        const { className, ...passthrough } = props as {
          className?: string
        } & Record<string, unknown>
        const Element: ElementType = Component
        return <Element ref={ref} className={cx(styles[slotKey], className)} {...passthrough} />
      },
    )
    Styled.displayName = `${name}${capitalize(slotKey)}`
    return Styled
  }

  return { StyleProvider, useSlotStyles, withContext, withRootProvider }
}
